<!DOCTYPE html>
<html lang="zh_cn">

<head>
  <meta charset="UTF-8" />
  <link rel="shortcut icon" type="image/x-icon" href="data:image/x-icon;base64,">
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <meta name="renderer" content="webkit" />
  <meta name="force-rendering" content="webkit" />
  <meta http-equiv="X-UA-Compatible" content="IE=Edge,chrome=1" />
  <title>区块链+司法鉴定机构管理信息系统</title>
  <script>
    // 获取当前页面的URL
    const currentUrl = window.location.href
    // 提取基础URL（协议 + 主机 + 端口）
    const url = new URL(currentUrl)
    const pathParts = url.pathname.split('/').filter((part) => part)
    const officeShortName = pathParts[0] || ''
    /* window.BASE_URL = `${url.protocol}//${url.hostname}${
      url.port ? `:${url.port}` : ''
    }/api/` */
    window.BASE_URL = `${url.protocol}//${url.hostname}${url.port ? `:${url.port}` : ''
      }/${officeShortName}/api/`
    window.COMPANY_NAME = '深光'
  </script>
  <style>
    #app {
      min-width: 1600px;
    }

    /*全局滚动条样式*/
    ::-webkit-scrollbar {
      /*滚动条整体样式*/
      width: 5px;
      /*高宽分别对应横竖滚动条的尺寸*/
      height: 5px;
    }

    ::-webkit-scrollbar-thumb {
      /*滚动条里面小方块*/
      -webkit-box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2);
      background: rgb(var(--primary-6));
    }

    ::-webkit-scrollbar-track {
      /*滚动条里面轨道*/
      -webkit-box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2);
      border-radius: 5px;
      background: rgba(150, 149, 149, 0.1);
    }
  </style>
  <script type="module" crossorigin src="/assets/index.35618b0a.js"></script>
  <link rel="modulepreload" crossorigin href="/assets/arco.93d87e4a.js">
  <link rel="modulepreload" crossorigin href="/assets/vue.01692e01.js">
  <link rel="modulepreload" crossorigin href="/assets/chart.79d621fb.js">
  <link rel="stylesheet" href="/assets/index.a7991558.css">
</head>

<body>
  <div id="app"></div>

</body>

</html>

