var ctx = "\/reuse\/";
$("[data-toggle='tooltip']").tooltip();
if(!String.prototype.replaceAll) {
	String.prototype.replaceAll = function(pattern, replaceValue) {
		const regex = new RegExp(pattern, 'g');
		return this.replace(regex, replaceValue);
	}
}
var userLang = "zh_CN";

        var prefix = ctx + "meta/etlDatasource";

        $(function() {
            var options = {
               	code: "id",
       		    parentCode: "pid",
       		    uniqueId: "id",
                url: prefix + "/list",
                createUrl: prefix + "/add",
                updateUrl: prefix + "/edit/{id}",
                removeUrl: prefix + "/remove",
				exportUrl: prefix + "/export",
                importUrl: prefix + "/importData",
                importTemplateUrl: prefix + "/importTemplate",
                modalName: "数据源",
			 	search: false,
                showSearch:false,
		        showExport: false,
                showRefresh: false,
                showColumns: false,
                showToggle: false, 
                type:"POST",
                columns: [
		 		{
					field : 'id', 
					title : '编号',
					visible: false,
                    sortable: false
				}, 
				{
					field : 'name', 
					title : '数据源名称',
                 	 width:'15',
                	 widthUnit:"%",
					sortable: false,
